<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>2048</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    body {
      background: #121212;
      color: #f9f6f2;
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      display: flex;
      justify-content: center;
      align-items: center;
      min-height: 100vh;
    }
    .container {
      text-align: center;
      max-width: 500px;
      padding: 20px;
      margin: auto;
    }
    #score {
      font-size: 28px;
      margin-bottom: 20px;
      font-weight: bold;
    }
    #board {
      display: grid;
      grid-template-columns: repeat(4, 1fr);
      gap: 10px;
      background: #3c3a32;
      padding: 10px;
      border-radius: 12px;
      width: fit-content;
      margin: 0 auto 20px;
      box-shadow: 0 8px 20px rgba(0,0,0,0.5);
    }
    .tile {
      width: 80px;
      height: 80px;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 28px;
      font-weight: bold;
      border-radius: 8px;
      background: #2d2b27;
      color: #f9f6f2;
      transition: all 0.12s ease;
      user-select: none;
    }
    .tile:empty {
      background: #2d2b27;
    }
    #reset {
      padding: 12px 28px;
      font-size: 18px;
      background: #555;
      color: #fff;
      border: none;
      border-radius: 8px;
      cursor: pointer;
      font-weight: bold;
      transition: background 0.2s;
    }
    #reset:hover {
      background: #777;
    }
  </style>
</head>
<body>
  <div class="container">
    <div id="score">0</div>
    <div id="board"></div>
    <button id="reset">New Game</button>
  </div>
  <script>
    (function () {
      const SIZE = 4;
      let grid = [];
      let score = 0;
      const boardEl = document.getElementById('board');
      const scoreEl = document.getElementById('score');
      const cells = [];

      // create tile elements
      for (let r = 0; r < SIZE; r++) {
        for (let c = 0; c < SIZE; c++) {
          const cell = document.createElement('div');
          cell.className = 'tile';
          boardEl.appendChild(cell);
          cells.push(cell);
        }
      }

      function updateBoard() {
        scoreEl.textContent = score;
        for (let r = 0; r < SIZE; r++) {
          for (let c = 0; c < SIZE; c++) {
            const val = grid[r][c];
            const cell = cells[r * SIZE + c];
            cell.textContent = val || '';
            if (val === 0) {
              cell.style.backgroundColor = '#2d2b27';
              cell.style.color = '#f9f6f2';
            } else {
              const colorMap = {
                2: { bg: '#2ecc71', color: '#fff' },
                4: { bg: '#27ae60', color: '#fff' },
                8: { bg: '#f39c12', color: '#fff' },
                16: { bg: '#e67e22', color: '#fff' },
                32: { bg: '#d35400', color: '#fff' },
                64: { bg: '#c0392b', color: '#fff' },
                128: { bg: '#8e44ad', color: '#fff' },
                256: { bg: '#2980b9', color: '#fff' },
                512: { bg: '#1abc9c', color: '#fff' },
                1024: { bg: '#16a085', color: '#fff' },
                2048: { bg: '#f1c40f', color: '#333' },
              };
              const style = colorMap[val] || { bg: '#e74c3c', color: '#fff' };
              cell.style.backgroundColor = style.bg;
              cell.style.color = style.color;
            }
          }
        }
      }

      function spawnTile() {
        const empties = [];
        for (let r = 0; r < SIZE; r++) {
          for (let c = 0; c < SIZE; c++) {
            if (grid[r][c] === 0) empties.push({ r, c });
          }
        }
        if (empties.length === 0) return;
        const { r, c } = empties[Math.floor(Math.random() * empties.length)];
        grid[r][c] = Math.random() < 0.9 ? 2 : 4;
      }

      function slideRow(row) {
        const tiles = row.filter(v => v !== 0);
        const result = [];
        let addedScore = 0;
        let i = 0;
        while (i < tiles.length) {
          if (i + 1 < tiles.length && tiles[i] === tiles[i + 1]) {
            const merged = tiles[i] * 2;
            result.push(merged);
            addedScore += merged;
            i += 2;
          } else {
            result.push(tiles[i]);
            i++;
          }
        }
        while (result.length < SIZE) result.push(0);
        return { row: result, addedScore };
      }

      function gridEqual(a, b) {
        for (let r = 0; r < SIZE; r++) {
          for (let c = 0; c < SIZE; c++) {
            if (a[r][c] !== b[r][c]) return false;
          }
        }
        return true;
      }

      function move(direction) {
        const oldGrid = grid.map(row => [...row]);
        const newGrid = Array.from({ length: SIZE }, () => Array(SIZE).fill(0));
        let totalAddedScore = 0;

        if (direction === 'left') {
          for (let r = 0; r < SIZE; r++) {
            const { row, addedScore } = slideRow(oldGrid[r]);
            newGrid[r] = row;
            totalAddedScore += addedScore;
          }
        } else if (direction === 'right') {
          for (let r = 0; r < SIZE; r++) {
            const rev = [...oldGrid[r]].reverse();
            const { row: slidRev, addedScore } = slideRow(rev);
            newGrid[r] = slidRev.reverse();
            totalAddedScore += addedScore;
          }
        } else if (direction === 'up') {
          for (let c = 0; c < SIZE; c++) {
            const col = [oldGrid[0][c], oldGrid[1][c], oldGrid[2][c], oldGrid[3][c]];
            const { row: slidCol, addedScore } = slideRow(col);
            for (let r = 0; r < SIZE; r++) newGrid[r][c] = slidCol[r];
            totalAddedScore += addedScore;
          }
        } else if (direction === 'down') {
          for (let c = 0; c < SIZE; c++) {
            const col = [oldGrid[0][c], oldGrid[1][c], oldGrid[2][c], oldGrid[3][c]];
            const revCol = [...col].reverse();
            const { row: slidRevCol, addedScore } = slideRow(revCol);
            const slidCol = slidRevCol.reverse();
            for (let r = 0; r < SIZE; r++) newGrid[r][c] = slidCol[r];
            totalAddedScore += addedScore;
          }
        } else {
          return false;
        }

        const changed = !gridEqual(oldGrid, newGrid);
        if (changed) {
          grid = newGrid;
          score += totalAddedScore;
          spawnTile();
          updateBoard();
          return true;
        }
        return false;
      }

      function resetGame() {
        grid = Array.from({ length: SIZE }, () => Array(SIZE).fill(0));
        score = 0;
        spawnTile();
        spawnTile();
        updateBoard();
      }

      function board() {
        return grid.map(row => [...row]);
      }

      function setBoard(arr) {
        grid = arr.map(row => [...row]);
        updateBoard();
      }

      function getScore() {
        return score;
      }

      // public API
      window.game = {
        size: SIZE,
        reset: resetGame,
        move: move,
        board: board,
        setBoard: setBoard,
        score: getScore,
      };

      // start a new game
      resetGame();

      // arrow key controls
      document.addEventListener('keydown', (e) => {
        if (e.key.startsWith('Arrow')) {
          e.preventDefault();
          const dirMap = {
            ArrowLeft: 'left',
            ArrowRight: 'right',
            ArrowUp: 'up',
            ArrowDown: 'down',
          };
          move(dirMap[e.key]);
        }
      });

      // reset button
      document.getElementById('reset').addEventListener('click', resetGame);
    })();
  </script>
</body>
</html>
